external_knowledge:
- 'shining brightly' refers to the top performers in terms of goals;
- 'each shining brightly in the constellation of seasons' refers to the player's top performance in each season;
- 'beacon players' are metaphorically the most influential players based on their performance metrics;
- 'captured the most stars' means having the highest number of goals among their records;
- 'top ten brightest stars' refers to limiting the results to the top ten players with the highest goals.

- "celestial dance" metaphorically refers to a match or game;
- "arena of Milan" is a metaphor for Stadio San Siro, located in Milan, Italy;
- "2020 season" refers to the year 2020;
- "perform" metaphorically refers to play in the match.

sql:
SELECT player_id, name, team_id, market_value
FROM players
WHERE market_value > 10000000;

SELECT match_id, date, team_id_1, team_id_2
FROM matches
ORDER BY date;

SELECT team_name
FROM teams
WHERE team_id = 1;

SELECT match_id, date
FROM matches
ORDER BY date ASC;

SELECT AVG(attendance) AS average_attendance
FROM matches
WHERE year = '2020';

SELECT DISTINCT t.team_name
FROM teams t
JOIN seasons s ON t.team_id = s.champion_team_id;

SELECT league, COUNT(*) AS total_teams
FROM teams
GROUP BY league;
